import{c as n}from"./app.8935f5f1.js";const s={},a=n('<h2 id="span的赋值与取值" tabindex="-1"><a class="header-anchor" href="#span的赋值与取值" aria-hidden="true">#</a> span的赋值与取值</h2><div class="language-html ext-html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>span</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>span_id<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>span的文本<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>span</span><span class="token punctuation">&gt;</span></span>的取值。\n<span class="token comment">&lt;!--  \njs取&lt;span&gt;的值并不是用\n    document.getElementById(&#39;span_noticesg&#39;).value，\n    而是\n    document.getElementById(&#39;span_id&#39;).innerText。\njquery取&lt;span&gt;的值，是\n    $(&quot;#span_noticesg&quot;).html();\n     --&gt;</span>\n``` \n- <span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>span</span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>span_id<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>span</span><span class="token punctuation">&gt;</span></span>的赋值。\n```js\n$(&#39;#span_id&#39;).html(&quot;span的文本&quot;);\ndocument.getElementById(&#39;span_id&#39;).innerText=&quot;span的文本&quot;; \n</code></pre></div><h5 id="jquery给p标签赋值的方法-bq-html-内容" tabindex="-1"><a class="header-anchor" href="#jquery给p标签赋值的方法-bq-html-内容" aria-hidden="true">#</a> jquery给p标签赋值的方法：<code>$(&quot;#bq&quot;).html(&quot;内容&quot;)；</code></h5><div class="language-javascript ext-js"><pre class="language-javascript"><code><span class="token comment">// 下载 for ajax</span>\n  <span class="token keyword">function</span> <span class="token function">downloadMB</span><span class="token punctuation">(</span><span class="token parameter">href</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n\t  \n         <span class="token keyword">var</span> $form <span class="token operator">=</span> <span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;&lt;form method=&quot;post&quot;&gt;&lt;/form&gt;&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n         $form<span class="token punctuation">.</span><span class="token function">attr</span><span class="token punctuation">(</span><span class="token string">&#39;action&#39;</span><span class="token punctuation">,</span>href<span class="token punctuation">)</span><span class="token punctuation">;</span>\n         $form<span class="token punctuation">.</span><span class="token function">appendTo</span><span class="token punctuation">(</span><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;body&#39;</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n         $form<span class="token punctuation">.</span><span class="token function">submit</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n         $form<span class="token punctuation">.</span><span class="token function">remove</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n <span class="token punctuation">}</span>\n\n</code></pre></div><h2 id="判断复选框是否选中状态" tabindex="-1"><a class="header-anchor" href="#判断复选框是否选中状态" aria-hidden="true">#</a> 判断复选框是否选中状态</h2><p>第一种是prop(‘checked’);</p><p>示例代码</p><div class="language-html ext-html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">type</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>checkbox<span class="token punctuation">&quot;</span></span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>checks<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">\n\t<span class="token comment">//获取文本框</span>\n\t<span class="token keyword">let</span> c1 <span class="token operator">=</span> <span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&quot;#checks&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">prop</span><span class="token punctuation">(</span><span class="token string">&#39;checked&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\t<span class="token comment">//得到c1为true或者false</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>第二种方法是is(“checked”)</p><div class="language-html ext-html"><pre class="language-html"><code><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>input</span> <span class="token attr-name">type</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>checkbox<span class="token punctuation">&quot;</span></span> <span class="token attr-name">id</span><span class="token attr-value"><span class="token punctuation attr-equals">=</span><span class="token punctuation">&quot;</span>checks<span class="token punctuation">&quot;</span></span><span class="token punctuation">&gt;</span></span>\n\n<span class="token tag"><span class="token tag"><span class="token punctuation">&lt;</span>script</span><span class="token punctuation">&gt;</span></span><span class="token script"><span class="token language-javascript">\n\t<span class="token comment">//获取文本框</span>\n\t<span class="token keyword">let</span> c1 <span class="token operator">=</span> <span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&quot;#checks&quot;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">is</span><span class="token punctuation">(</span><span class="token string">&#39;checked&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n\t<span class="token comment">//得到c1为true或者false</span>\n</span></span><span class="token tag"><span class="token tag"><span class="token punctuation">&lt;/</span>script</span><span class="token punctuation">&gt;</span></span>\n</code></pre></div><p>如果复选框不确定数量或者多个的话，需要使用each相同名字或者类型的复选框。</p><div class="language-javascript ext-js"><pre class="language-javascript"><code><span class="token function">$</span><span class="token punctuation">(</span><span class="token string">&#39;input[type=&#39;</span>checkbox<span class="token string">&#39;]:checked&#39;</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">each</span><span class="token punctuation">(</span><span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">{</span>\n  \t <span class="token function">$</span><span class="token punctuation">(</span><span class="token keyword">this</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">is</span><span class="token punctuation">(</span><span class="token string">&#39;checked&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n</code></pre></div>',12);s.render=function(n,s){return a};export{s as default};
